var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"투화님. 문제가 생겼습니다.","JPN":"投花様、問題が発生しました。","ENG":"Ms. Flora. A problem has arisen.","TWN":"投花師姐，出事了。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"오늘은 꽃술 향이 좋네. 너도 마실래?","JPN":"今日は花酒の香りがやけに良い。お前も飲むか？","ENG":"The scent of today's floral spirit is nice. Would you also like a sip?","TWN":"今天的花酒很香呢，你要來一杯嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"아, 네… 감사합니다.","JPN":"あ、はい……ありがとうございます。","ENG":"Oh, yes... Thank you.","TWN":"喔，好…謝謝。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그래서, 뭐가 문제지?","JPN":"それで、何があった？","ENG":"So? What might be the problem?","TWN":"所以是出什麼事？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"문주님이 그 파문인에게 노려지고 있는 것 같습니다.","JPN":"門主様があの追放者に狙われているようです。","ENG":"We believe that our sect leader is being targeted by that outcast.","TWN":"幫主似乎被那個逐出師門的人給盯上了。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"살수들을 파견할까요?","JPN":"刺客を送り込みましょうか？","ENG":"Shall I deploy the assassins?","TWN":"要派殺手嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭐 하러?","JPN":"どうしてだ？","ENG":"What for?","TWN":"為何要派？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"그야 문주님의 신변에 위험이 생길 수 있고…","JPN":"それは、門主様の身に危険が及ぶかもしれませんし……","ENG":"Because our sect leader is in danger...","TWN":"我擔心幫主可能會有危險…"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"만일 그 자가 결투에서 이겨 백서의 문주가 되기라도 한다면…","JPN":"もしその者が決闘で勝利し、白西の門主になるようなことでもあれば……","ENG":"And if that man wins the battle and becomes the leader of White West...","TWN":"萬一他在決鬥中獲勝成為白西的幫主…"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"전통을 지켜야 할 우리가 섭리음양의 법칙을 먼저 깨부수는 건 곤란해.","JPN":"伝統を守っていく立場の私たちが燮理陰陽のルールを自ら破ることはできない。","ENG":"We are bound by tradition, and breaking the balance of yin and yang will not be tolerated.","TWN":"我們本該要遵守燮理陰陽的規矩，怎麼可以先破壞規矩呢？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"아무리 불명예스럽게 쫓겨난 파문인이라 해도, 그자 또한 간장의 조각을 가진 이상 평등한 백서의 도전자이니까.","JPN":"いくらあの者が不祥事によって追放された身だとしても、干将の欠片を持っている以上、あの者もまた白西の正当な挑戦者だからな。","ENG":"No matter how dishonorably this man has been excommunicated, he still wields the shard of Kanshou. Thus, he has the right to challenge her without question.","TWN":"雖然他是做了不光榮的事才被逐出師門的，但他身上也有干將的碎片，那他就應該有公平競爭的機會。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"괜찮을까요?","JPN":"それで大丈夫なんでしょうか？","ENG":"Will she be okay?","TWN":"這樣沒問題嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"걱정 마. 문주님의 혈귀라는 별호는 단지 멋으로 붙은 게 아니거든.","JPN":"心配するな。門主様の血鬼という異名は、伊達じゃないのだ。","ENG":"Do not worry. Her nickname of Bloodseeker is not just for show.","TWN":"放心，你以為幫主血鬼的稱號只是取好聽的嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"설마, 장문인께서 내게 맡긴 문주 자리를 고작 사사로운 정 때문에 그 애한테 넘긴 거라고 생각하니?","JPN":"まさか、掌門人が私に任せた門主の座をただの人情で師妹に譲ったと思うか？","ENG":"Or, do you think that I yielded the seat of sect leader to her because of some trivial attachment I have toward her?","TWN":"你以為掌門人只是因為個人喜好，就將原本要託付於我的幫主之位交給她嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"그 자와 엮이게 될 것까지… 예상하고 계셨던 겁니까?","JPN":"あの者といずれ交わることになることを……見越してのことだったのでしょうか？","ENG":"Then you already predicted... that he would approach her?","TWN":"意思是掌門人他…早就料到那個人會來糾纏幫主嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"파문인 타오는 흑동의 여러 골칫거리들 중 하나일 뿐이야.","JPN":"追放者であるタオは黒東にある数多くの問題事の一つに過ぎない。","ENG":"The outcast known as Tao is one of many nuisances for Black East.","TWN":"被逐出師門的陶只是黑東的眾多麻煩之一。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그리고 장문인이 계시던 과거와 달리 지금 세상은 어딜 가나 괴물천지잖아.","JPN":"そして掌門人がまだいらっしゃった昔とは違い、今の世はどこも怪物だらけだ。","ENG":"Furthermore, the world is full of monsters, unlike during the previous sect master's time.","TWN":"況且，不同於過去掌門人還在世時，現在的世界怪物無所不在。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"이런 엉망진창 산해경 속에서…","JPN":"こんなめちゃくちゃな世界で……","ENG":"In this torrent of chaos...","TWN":"在這一塌糊塗的山海經中…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};